"use strict";(self.webpackChunkdocs_site=self.webpackChunkdocs_site||[]).push([["3398"],{3544(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/numa-portfolio/docs/simple-explanation","label":"Explain Like I\'m 10: High Frequency Trading","docId":"simple-explanation","unlisted":false},{"type":"category","label":"NUMA SPSC Ring Buffer","items":[{"type":"link","href":"/numa-portfolio/docs/introduction","label":"Introduction & FinTech Context","docId":"introduction","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/hardware-architecture","label":"Hardware Architecture & The Physical Reality","docId":"hardware-architecture","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/software-primitives","label":"Software Primitives & Concurrency","docId":"software-primitives","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/system-design","label":"System Design & Architecture","docId":"system-design","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/benchmarking","label":"Benchmarking Hardware Latency","docId":"benchmarking","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/results-analysis","label":"Results & Analysis","docId":"results-analysis","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"HFT Limit Order Book","items":[{"type":"link","href":"/numa-portfolio/docs/lob-introduction","label":"The HFT Limit Order Book","docId":"lob-introduction","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/big-picture","label":"Big Picture Architecture","docId":"big-picture","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/lob-system-design","label":"Zero-Allocation System Design","docId":"lob-system-design","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/lob-data-structures","label":"O(1) Data Structures","docId":"lob-data-structures","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/lob-cpp-features","label":"C++ Implementation Details","docId":"lob-cpp-features","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/lob-benchmarking","label":"Before vs After Benchmark","docId":"lob-benchmarking","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"End-to-End Pipeline","items":[{"type":"link","href":"/numa-portfolio/docs/itch-pipeline-architecture","label":"E2E System Design","docId":"itch-pipeline-architecture","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/ouch-protocol-gateway","label":"OUCH 4.2 Egress","docId":"ouch-protocol-gateway","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/tcp-egress-networking","label":"TCP Egress Network","docId":"tcp-egress-networking","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/pre-trade-risk-engine","label":"Pre-Trade Risk","docId":"pre-trade-risk-engine","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/strategy-engine-framework","label":"Strategy Engine","docId":"strategy-engine-framework","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/execution-management-system","label":"EMS & Epoll Loop","docId":"execution-management-system","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/async-lock-free-logger","label":"Lock-Free Logging","docId":"async-lock-free-logger","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/exchange-emulator","label":"Exchange Emulator","docId":"exchange-emulator","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/tick-to-trade-metrics","label":"Tick-to-Trade Pipeline","docId":"tick-to-trade-metrics","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"System Architecture (UML)","items":[{"type":"link","href":"/numa-portfolio/docs/uml/uml-Communication_diagram","label":"Communication Diagram","docId":"uml/uml-Communication_diagram","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/uml/uml-activity_diagram","label":"Activity Diagram","docId":"uml/uml-activity_diagram","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/uml/uml-class_diagram","label":"Class Diagram","docId":"uml/uml-class_diagram","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/uml/uml-component_diagram","label":"Component Diagram","docId":"uml/uml-component_diagram","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/uml/uml-composite_structure_diagram","label":"Composite Structure Diagram","docId":"uml/uml-composite_structure_diagram","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/uml/uml-deployment_diagram","label":"Deployment Diagram","docId":"uml/uml-deployment_diagram","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/uml/uml-interaction_overview_diagram","label":"Interaction Overview Diagram","docId":"uml/uml-interaction_overview_diagram","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/uml/uml-object_diagram","label":"Object Diagram","docId":"uml/uml-object_diagram","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/uml/uml-package_diagram","label":"Package Diagram","docId":"uml/uml-package_diagram","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/uml/uml-profile_diagram","label":"Profile Diagram","docId":"uml/uml-profile_diagram","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/uml/uml-sequence_diagram","label":"Sequence Diagram","docId":"uml/uml-sequence_diagram","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/uml/uml-statemachine_diagram","label":"Statemachine Diagram","docId":"uml/uml-statemachine_diagram","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/uml/uml-timing_diagram","label":"Timing Diagram","docId":"uml/uml-timing_diagram","unlisted":false},{"type":"link","href":"/numa-portfolio/docs/uml/uml-usecase_diagram","label":"Usecase Diagram","docId":"uml/uml-usecase_diagram","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"async-lock-free-logger":{"id":"async-lock-free-logger","title":"Async Lock-Free Logger","description":"In a High-Frequency Trading system, observability is paramount. However, standard logging libraries typically rely on mutexes or synchronous file I/O, which introduce catastrophic latency spikes (jitter) into the critical path.","sidebar":"tutorialSidebar"},"benchmarking":{"id":"benchmarking","title":"Benchmarking Hardware Latency","description":"To accurately measure the performance of our SPSC ring buffer, we must measure sub-microsecond latencies. When testing the performance of a software system, developers typically use standard libraries like std::chrono in C++ or System.nanoTime() in Java.","sidebar":"tutorialSidebar"},"big-picture":{"id":"big-picture","title":"End-to-End Architecture","description":"To truly understand how the components of this project fit together, we need to look at the \\"Big Picture\\" system design. High-Frequency Trading (HFT) systems require multiple components working in perfect harmony, typically broken down into networking, message decoding, order routing, and order matching.","sidebar":"tutorialSidebar"},"exchange-emulator":{"id":"exchange-emulator","title":"Exchange Emulator","description":"Testing a High-Frequency Trading (HFT) system requires a reliable, deterministic, and low-latency mock exchange. Our repository includes a built-in ExchangeEmulator designed to validate the end-to-end tick-to-trade pipeline on a single machine.","sidebar":"tutorialSidebar"},"execution-management-system":{"id":"execution-management-system","title":"Execution Management System","description":"Sending an order to the exchange is only half of the execution equation. The HFT pipeline must asynchronously track the state of that order, handle exchange acknowledgments, and manage the underlying network events efficiently. This is handled by the Execution Management System (EMS) and the NetworkEventLoop.","sidebar":"tutorialSidebar"},"hardware-architecture":{"id":"hardware-architecture","title":"Hardware Architecture & The Physical Reality","description":"To write ultra-fast software, you must understand the physical hardware it runs on. The concept of Mechanical Sympathy means designing your software to align with the limitations and architectures of the hardware. This chapter explores the hidden mechanisms inside modern servers that dictate memory latency.","sidebar":"tutorialSidebar"},"introduction":{"id":"introduction","title":"Introduction & FinTech Context","description":"Welcome to the NUMA-Aware Lock-Free SPSC Ring Buffer project. This documentation serves as a step-by-step guide for students and professionals to understand the theory, hardware realities, and system design behind an ultra-low-latency inter-thread communication mechanism used in High-Frequency Trading (HFT).","sidebar":"tutorialSidebar"},"itch-pipeline-architecture":{"id":"itch-pipeline-architecture","title":"ITCH Decoder & E2E Pipeline","description":"This section details the complete, integrated architecture of the High-Frequency Trading (HFT) pipeline built in this repository. It traces the journey of a market data packet from its raw binary form, through our NUMA-aware inter-thread transport, to its final resting place in our Zero-Allocation Limit Order Book (LOB).","sidebar":"tutorialSidebar"},"lob-benchmarking":{"id":"lob-benchmarking","title":"LOB Benchmarking","description":"To demonstrate the impact of our zero-allocation, cache-aligned design, we benchmarked our highly optimized LimitOrderBook against a typical standard library approach (NaiveOrderBook).","sidebar":"tutorialSidebar"},"lob-cpp-features":{"id":"lob-cpp-features","title":"C++ Implementation Details","description":"The Limit Order Book leverages specific C++ features to enforce safety, prevent accidental overhead, and interface directly with the underlying operating system.","sidebar":"tutorialSidebar"},"lob-data-structures":{"id":"lob-data-structures","title":"O(1) Data Structures","description":"The theoretical limit for order book operations (add, cancel, modify) is O(1)\u2014constant time. To achieve this in practice without hitting hidden O(N) bottlenecks requires carefully chosen, interconnected data structures.","sidebar":"tutorialSidebar"},"lob-introduction":{"id":"lob-introduction","title":"The HFT Limit Order Book","description":"Welcome to the Limit Order Book (LOB) implementation guide. This section of the documentation dives deep into the architecture, design, and C++ engineering behind a high-performance matching engine suitable for High-Frequency Trading (HFT).","sidebar":"tutorialSidebar"},"lob-system-design":{"id":"lob-system-design","title":"Zero-Allocation System Design","description":"Achieving ultra-low, deterministic latency requires designing the Limit Order Book (LOB) with hardware sympathies in mind. The architecture must align with how modern CPUs cache and fetch memory.","sidebar":"tutorialSidebar"},"ouch-protocol-gateway":{"id":"ouch-protocol-gateway","title":"OUCH 4.2 Protocol Gateway","description":"If the ITCH 5.0 protocol is how our HFT system listens to the market, the OUCH 4.2 protocol is how it speaks to it.","sidebar":"tutorialSidebar"},"pre-trade-risk-engine":{"id":"pre-trade-risk-engine","title":"Pre-Trade Risk Engine","description":"In high-frequency trading, software bugs or algorithmic feedback loops can generate millions of erroneous orders in seconds\u2014a scenario that has bankrupted real-world trading firms (e.g., Knight Capital).","sidebar":"tutorialSidebar"},"results-analysis":{"id":"results-analysis","title":"Results & Analysis","description":"This page visualizes the results from our 1,000,000 message test runs, comparing Local NUMA (Thread and Memory on the same node) against Cross NUMA (Thread and Memory on different nodes).","sidebar":"tutorialSidebar"},"simple-explanation":{"id":"simple-explanation","title":"Explain Like I\'m 10: High Frequency Trading","description":"Imagine you are playing a massive, fast-paced video game where the goal is to buy and sell rare trading cards. The rules are simple:","sidebar":"tutorialSidebar"},"software-primitives":{"id":"software-primitives","title":"Software Primitives & Concurrency","description":"To overcome the hardware limitations discussed in the previous chapter, we must use precise software engineering techniques. This chapter explores the C++ concepts and concurrency primitives that allow our SPSC ring buffer to achieve wait-free progress.","sidebar":"tutorialSidebar"},"strategy-engine-framework":{"id":"strategy-engine-framework","title":"Strategy Engine Framework","description":"At the heart of the decision-making process lies the Strategy Engine. It bridges the gap between passive market data ingestion and active order execution. The framework is designed to be highly modular, allowing quantitative researchers to deploy multiple distinct alpha models without modifying the core ultra-low latency infrastructure.","sidebar":"tutorialSidebar"},"system-design":{"id":"system-design","title":"System Design & Architecture","description":"This chapter brings together the hardware realities and the software primitives to present the complete High-Level and Low-Level architecture of the NUMA-aware SPSC ring buffer.","sidebar":"tutorialSidebar"},"tcp-egress-networking":{"id":"tcp-egress-networking","title":"TCP Egress Networking","description":"In a tick-to-trade pipeline, transmitting the decision to the exchange is just as critical as receiving market data. The TCPEgress module handles the reliable, ultra-low latency transmission of OUCH protocol messages back to the exchange.","sidebar":"tutorialSidebar"},"tick-to-trade-metrics":{"id":"tick-to-trade-metrics","title":"Tick-to-Trade E2E Benchmark","description":"The definitive metric for any High-Frequency Trading firm is its Tick-to-Trade latency: the time elapsed from the moment a market data packet (\\"Tick\\") triggers an algorithmic decision, to the moment the system issues an order (\\"Trade\\") to the network buffer.","sidebar":"tutorialSidebar"},"uml/uml-activity_diagram":{"id":"uml/uml-activity_diagram","title":"Activity Diagram","description":"This document contains the detailed activity diagram of the numa-portfolio project, illustrating the complete end-to-end flow from system initialization, through the concurrent execution of the Network and Strategy threads, to market data processing, order evaluation, risk checks, and system shutdown.","sidebar":"tutorialSidebar"},"uml/uml-class_diagram":{"id":"uml/uml-class_diagram","title":"Class Diagram","description":"This document contains a high-level class diagram of the HFT Local Project showcasing the core classes and their relationships.","sidebar":"tutorialSidebar"},"uml/uml-Communication_diagram":{"id":"uml/uml-Communication_diagram","title":"Communication Diagram","description":"This document contains the Communication Diagram (UML) for the numa-portfolio project, capturing the objects involved in the system and the numbered sequence of messages exchanged between them.","sidebar":"tutorialSidebar"},"uml/uml-component_diagram":{"id":"uml/uml-component_diagram","title":"Component Diagram","description":"This document contains the component diagram for the numa-portfolio project, illustrating the logical grouping of components, their responsibilities, and how data and control flow between them across various architectural layers.","sidebar":"tutorialSidebar"},"uml/uml-composite_structure_diagram":{"id":"uml/uml-composite_structure_diagram","title":"Composite Structure Diagram","description":"A Composite Structure Diagram illustrates the internal structure of a class or component, including its parts, ports, and connectors. Below is the Mermaid representation of the numa-portfolio project\'s internal structure.","sidebar":"tutorialSidebar"},"uml/uml-deployment_diagram":{"id":"uml/uml-deployment_diagram","title":"Deployment Diagram","description":"This deployment diagram illustrates the physical and logical architecture of the entire NUMA-aware High-Frequency Trading project. It captures the interaction between the exchange emulator and the core HFT system, highlighting the specific hardware topology, threading model, and network communications.","sidebar":"tutorialSidebar"},"uml/uml-interaction_overview_diagram":{"id":"uml/uml-interaction_overview_diagram","title":"Interaction Overview Diagram","description":"An Interaction Overview Diagram provides a high-level, activity-diagram-like view of the flow of control across different interactions within a system. Each primary node (denoted by the ref subroutine shape) represents a distinct interaction or sequence diagram that encapsulates a specific functional phase of the numa-portfolio execution pipeline.","sidebar":"tutorialSidebar"},"uml/uml-object_diagram":{"id":"uml/uml-object_diagram","title":"Object Diagram","description":"This diagram represents a runtime snapshot of the HFT Local Project as instantiated in Main.cpp. It illustrates the key object instances, their thread affinity, and their relationships during system execution.","sidebar":"tutorialSidebar"},"uml/uml-package_diagram":{"id":"uml/uml-package_diagram","title":"Package Diagram","description":"The following class/package diagram details the module structure and runtime inter-package dependencies of the numa-portfolio high-frequency trading (HFT) project. The system is logically grouped into explicit namespaces reflecting core logic, wire protocol parsers, risk management, and low-level hardware optimization utilities.","sidebar":"tutorialSidebar"},"uml/uml-profile_diagram":{"id":"uml/uml-profile_diagram","title":"Profile Diagram","description":"This document contains the UML Profile Diagram for the HFT Local Project, showcasing the domain-specific stereotypes, tagged values, and constraints applied to the architecture. The diagram utilizes Mermaid\'s class diagram capabilities to represent the profile.","sidebar":"tutorialSidebar"},"uml/uml-sequence_diagram":{"id":"uml/uml-sequence_diagram","title":"Sequence Diagram","description":"This document contains the detailed sequence diagram visualizing the execution flows and dynamic interactions of the numa-portfolio High-Frequency Trading (HFT) system.","sidebar":"tutorialSidebar"},"uml/uml-statemachine_diagram":{"id":"uml/uml-statemachine_diagram","title":"Statemachine Diagram","description":"This document contains comprehensive State Machine diagrams for the High-Frequency Trading (HFT) system, capturing the lifecycles and behaviors of the various components in the numa-portfolio codebase.","sidebar":"tutorialSidebar"},"uml/uml-timing_diagram":{"id":"uml/uml-timing_diagram","title":"Timing Diagram","description":"This document contains the timing and execution flow diagrams for the numa-portfolio high-frequency trading (HFT) system. The diagrams illustrate the exact sequence of events, concurrency points, and the continuous timeline from the moment a market data tick is received on the network interface to the moment an order is dispatched to the exchange.","sidebar":"tutorialSidebar"},"uml/uml-usecase_diagram":{"id":"uml/uml-usecase_diagram","title":"Usecase Diagram","description":"This document contains the comprehensive Use Case Diagram for the numa-portfolio project, illustrating the key actors (both human and external systems) and their interactions with the system\'s core functionalities, benchmarking suites, and high-frequency trading capabilities.","sidebar":"tutorialSidebar"}}}}')}}]);